(function(){"use strict";document.addEventListener("click",function(t){t.target.closest('[data-action="goBack"]')&&history.back()}),$('form[name="contactform"]').on("submit",function(t){t.preventDefault();var n=$(this),r=n.find('button[type="submit"]'),o=r.html(),i=n.data("api-url");if(!i){console.error("[contact-form] Missing data-api-url attribute on form"),window.usError("Configuration error \u2014 please refresh and try again.");return}r.prop("disabled",!0).html('<i class="fas fa-spinner fa-spin"></i> Sending...');var e={};n.serializeArray().forEach(function(a){e[a.name]=a.value}),new ElanRegistryAPI().post(i,e).then(function(a){window.usSuccess(a.message),n[0].reset()}).catch(function(a){console.error("Contact form submission failed:",a),window.usError(a.message||"Failed to send.")}).finally(function(){r.prop("disabled",!1).html(o)})})})();
